SELECT q.content
FROM tbl_survey_result r
JOIN tbl_survey_result_questions q ON r.result_id = q.result_id
WHERE r.title_id = #{resultId}
    AND r.participant = #{participant}
    AND q.survey_id IN (13, 14)
ORDER BY q.survey_id ASC;

SELECT cd
FROM tbl_codeinfo
WHERE cd_kor = #{category}
